				function GetPreviousPageName() {
                
                	// getting last page url

			        var lastVisitedPage = '';
			        var pagesRetrievedData = sessionStorage.getItem('pageInfo');
			
			        if (pagesRetrievedData) {
			            var pagesArray = JSON.parse(pagesRetrievedData );
			
			            var lastPageObj = pagesArray.find(m=>m.PageURL === document.referrer);
			
			            if (lastPageObj != null) {
			                lastVisitedPage = lastPageObj.PageTitle;
			            }
			        }
			        
			        return lastVisitedPage;
                
                }

                
                $(document).ready(function () {
                
                
                // setting current page in localstorage

				var retrievedData = sessionStorage.getItem('pageInfo');
				if (retrievedData) {
				    var pageInfoArray = JSON.parse(retrievedData);
				    
				    pageInfoArray.push({ PageURL: window.location.href, PageTitle: document.title });
				    sessionStorage.setItem('pageInfo', JSON.stringify(pageInfoArray));
				
				    
				} else {
				    var pageInfoArray = [
				    	{ PageURL: window.location.href, PageTitle: document.title }
					];
					
					sessionStorage.setItem('pageInfo', JSON.stringify(pageInfoArray));
				}
                
                
