                function PushDataGA(event, clickedUrl, segment, category, subCategory, buttonName) {
					
					if(buttonName == null) {
						buttonName = '';
					}
					
					//  Get current page 
					var currentPageUrl = "";
					if (typeof this.href === "undefined") {
						currentPageUrl = document.location.toString().toLowerCase();
					}
					else {
						currentPageUrl = this.href.toString().toLowerCase();
					}
					var sliteddata = currentPageUrl.split("/");
				
					var dataLayer = window.dataLayer || [];
					dataLayer.push({
						'event': event, 
						'language': sliteddata[3],
						'segment': segment,
						'category': category,
						'subCategory': subCategory,
						'loginStatus': '',
						'customerID': '',
						'buttonname': buttonName,
						'clickUrl': clickedUrl
					 });
				}
				
				
				function PushDataGAFooter(event, clickedUrl, segment, category, subCategory, ribbonElem) {
					
					if(ribbonElem == null) {
						ribbonElem = '';
					}
					
					//  Get current page 
					var currentPageUrl = "";
					if (typeof this.href === "undefined") {
						currentPageUrl = document.location.toString().toLowerCase();
					}
					else {
						currentPageUrl = this.href.toString().toLowerCase();
					}
					var sliteddata = currentPageUrl.split("/");
				
					var dataLayer = window.dataLayer || [];
					dataLayer.push({
						'event': event, 
						'language': sliteddata[3],
						'segment': segment,
						'category': category,
						'subCategory': subCategory,
						'loginStatus': '',
						'customerID': '',
						'ribbonElement': ribbonElem
					 });
				}



