window.onload = function() {  
  // Enhanced Data Layer Push Function  
  function pushToDataLayer(event, category, action, label, p_language, p_pagename, p_pagecategory, p_pagesubcategory, p_previouspagename, p_locationtype, p_location) {  
    window.dataLayer = window.dataLayer || [];  
    window.dataLayer.push({  
      event: event.toLowerCase(),  
      category: category ? category.toLowerCase() : null,  
      action: action ? action.toLowerCase() : null,  
      label: label ? label.toLowerCase() : null,  
      p_language: p_language.toLowerCase(),  
      p_pagename: p_pagename.toLowerCase(),  
      p_pagecategory: p_pagecategory.toLowerCase(),  
      p_pagesubcategory: p_pagesubcategory.toLowerCase(),  
      p_previouspagename: p_previouspagename.toLowerCase(),  
      p_locationtype: p_locationtype.toLowerCase(),  
      p_location: p_location.toLowerCase()  
    });  
  }  

  // Page Details Extraction Function  
  function getPageDetails() {  
    const pageTitle = document.title;  
    const previousPageTitle = sessionStorage.getItem('currentPageTitle') || 'direct';  
    const urlPath = window.location.pathname.split('/');  
    const pageCategory = urlPath[2] || '';  
    const pageSubCategory = urlPath[3] || '';  

    // Store the current page title in sessionStorage for the next page  
    sessionStorage.setItem('currentPageTitle', pageTitle);  

    return {  
      pageTitle,  
      pageCategory,  
      pageSubCategory,  
      previousPageTitle  
    };  
  }  

  // Get Current Page Details  
  const { pageTitle, pageCategory, pageSubCategory, previousPageTitle } = getPageDetails();  

  // Initial Page View Event  
  pushToDataLayer('e_pageview', null, null, null, 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  

  // Event Listeners Function  
  function addEventListenersToButtons() {  
    // Logo Click Event  
    document.querySelectorAll('.navbar-brand').forEach(button => {  
      button.addEventListener('click', () => {  
        pushToDataLayer('e_logoclick', 'header interaction', 'button click', 'bank muscat logo', 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Search Button Click Event  
    document.querySelectorAll('.ms-srch-sb').forEach(button => {  
      button.addEventListener('click', () => {  
        const searchTerm = document.querySelector('.ms-srch-sb input').value || '[keyword]';  
        pushToDataLayer('e_search', 'header interaction', 'search button', searchTerm, 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Branch Locator Click Event  
    document.querySelectorAll('.find_us').forEach(link => {  
      link.addEventListener('click', () => {  
        pushToDataLayer('e_locator', 'footer interaction', 'link click', 'branch & atm locator', 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Call Icon Click Event  
    document.querySelectorAll('.social_phone').forEach(link => {  
      link.addEventListener('click', () => {  
        pushToDataLayer('e_callicon', 'footer interaction', 'phone click', '2479 5555', 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Email Icon Click Event  
    document.querySelectorAll('.social_mail').forEach(link => {  
      link.addEventListener('click', () => {  
        pushToDataLayer('e_emailicon', 'footer interaction', 'email click', 'care@bankmuscat.com', 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Social Media Icon Click Events  
    const socialIcons = [  
      { selector: '.social_facebook', platform: 'facebook' },  
      { selector: '.social_twitter', platform: 'twitter' },  
      { selector: '.social_linkedin', platform: 'linkedin' },  
      { selector: '.social_insta', platform: 'instagram' },  
      { selector: '.social_youtube', platform: 'youtube' }  
    ];  

    socialIcons.forEach(({ selector, platform }) => {  
      document.querySelectorAll(selector).forEach(link => {  
        link.addEventListener('click', () => {  
          pushToDataLayer('e_socialicon', 'footer interaction', 'social media click', platform, 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
        });  
      });  
    });  

    // Additional Existing Event Listeners (from your previous implementation)  
    // Header Carousel Click Event  
    document.querySelectorAll('.hwslider').forEach(button => {  
      button.addEventListener('click', () => {  
        const bannerName = document.querySelector('.hwslider .active h2')?.textContent || 'discover world beyond banking';  
        pushToDataLayer('e_pageheadercarousel', 'header interaction', 'carousel click', bannerName, 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Page Body Carousel Click Event  
    document.querySelectorAll('.sy-controls').forEach(button => {  
      button.addEventListener('click', () => {  
        const bannerName = document.querySelector('.sy-active .banner-title')?.textContent || 'connect with us';  
        pushToDataLayer('e_pagebodycarousel', 'page body interaction', 'carousel click', bannerName, 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  

    // Page Body CTA Click Event  
    document.querySelectorAll('.activity-item').forEach(button => {  
      button.addEventListener('click', () => {  
        const ctaText = button.querySelector('h3')?.textContent || 'choose your card';  
        pushToDataLayer('e_pagebodycta', 'page body interaction', 'cta icons', ctaText, 'en', pageTitle, pageCategory, pageSubCategory, previousPageTitle, '', '');  
      });  
    });  
  }  

  // Initialize Event Listeners  
  addEventListenersToButtons();  
};

